`define CYCLE_TIME      15.0
`define SEED_NUMBER     69


`ifdef RTL
    `define PATTERN_NUMBER 1000
`endif
`ifdef GATE
    `define PATTERN_NUMBER 100
`endif

module PATTERN(
    clk,
    rst_n,
    in_valid,
    in_data,
    out_valid,
    out_data
);

output logic        clk, rst_n, in_valid;
output logic [7:0]  in_data;

input               out_valid;
input        [11:0] out_data;

parameter CYCLE = `CYCLE_TIME;
integer seed_int;

integer pat_count;
integer total_latency;
integer current_latency;
integer i, j, k;
integer gap;
integer r, c;
integer sum_F, sum_H;
integer out_count;

logic        golden_task_num;
logic [7:0]  golden_A  [0:3][0:3];
logic [7:0]  golden_B  [0:3][0:3];
logic [3:0]  golden_F1 [0:3][0:3];
logic [3:0]  golden_H1 [0:3][0:3];
logic [3:0]  golden_F2 [0:3][0:3];
logic [3:0]  golden_H2 [0:3][0:3];

logic [3:0]  X1 [0:3][0:3], X2 [0:3][0:3];
logic [7:0]  Y1 [0:3][0:3], Y2 [0:3][0:3];
logic [11:0] BX1[0:3][0:3], Mid_B[0:3][0:3];
logic [7:0]  Mid_A[0:3][0:3];
logic [11:0] Mid_AX2[0:3][0:3];

logic [11:0] ans_OUT_A [0:15];
logic [11:0] ans_OUT_B [0:15];
logic [11:0] expected_val;

logic check_idle_en;

//================================================================
//   GLOBAL PROTOCOL MONITOR 
//================================================================

always @(negedge clk) begin
    if (in_valid === 1'b1 && out_valid === 1'b1) begin
        $display("************************************************************");
        $display("* [VIOLATION] out_valid CANNOT overlap with in_valid!      *");
        $display("* Failed at Pattern NO.%4d                                *", pat_count);
        $display("************************************************************");
        terminate_sim_task();
    end
end

always @(negedge clk) begin
    if (rst_n === 1'b1 && check_idle_en === 1'b1 && out_valid === 1'b1) begin
        $display("************************************************************");
        $display("* [VIOLATION] out_valid MUST NOT be high during gap phase! *");
        $display("* Failed at Pattern NO.%4d                                *", pat_count);
        $display("************************************************************");
        terminate_sim_task();
    end
end

always #(CYCLE/2.0) clk = ~clk;

initial begin
    seed_int = `SEED_NUMBER;
    $srandom(seed_int);
    
    total_latency = 0;
    check_idle_en = 1'b0;
    
    rst_n = 1'b1;
    in_valid = 1'b0;
    in_data = 8'bx;
    
    force clk = 0;
    
    #(CYCLE / 2.0);
    rst_n = 1'b0;
    
    #(CYCLE * 2.0);
    
    reset_task();
    
    rst_n = 1'b1;
    #(CYCLE / 2.0);
    release clk;
    
    for (pat_count = 0; pat_count < `PATTERN_NUMBER; pat_count = pat_count + 1) begin
        generate_golden_data();
        compute_golden_model();
        wait_gap_task();
        drive_input_task();
        wait_out_valid_task();
        check_ans_task();
        $display("\033[0;32mCorrect Pattern NO.%4d \033[m", pat_count);
    end

    VERIFICATION_PASSED_TASK();
end

task reset_task;
begin
    if (out_valid !== 1'b0 || out_data !== 12'b0) begin
        $display("************************************************************");
        $display("* [VIOLATION] Output signals must be zero after reset!     *");
        $display("************************************************************");
        terminate_sim_task();
    end
end endtask

task generate_golden_data;
begin
    // Task Selection Logic (Including Burst Tests)
    if (pat_count < 2) golden_task_num = pat_count % 2;
    else if (pat_count < 4) golden_task_num = pat_count % 2;
    else if (pat_count == 8) golden_task_num = 0; // Divisor Edge Case
    else if (pat_count == 9) golden_task_num = 1; // Divisor Edge Case
    else if (pat_count >= 10 && pat_count < 20) golden_task_num = 0; // Burst Task 0
    else if (pat_count >= 20 && pat_count < 30) golden_task_num = 1; // Burst Task 1
    else golden_task_num = $urandom_range(0, 1);

    for (i = 0; i < 4; i = i + 1) begin
        for (j = 0; j < 4; j = j + 1) begin
            if (pat_count == 0 || pat_count == 1) begin
                // All Zeros
                golden_A[i][j]  = 8'h00; golden_B[i][j]  = 8'h00;
                golden_F1[i][j] = 4'h0;  golden_H1[i][j] = 4'h0;
                golden_F2[i][j] = 4'h0;  golden_H2[i][j] = 4'h0;
            end else if (pat_count == 2 || pat_count == 3) begin
                // All Max Values
                golden_A[i][j]  = 8'hFF; golden_B[i][j]  = 8'hFF;
                golden_F1[i][j] = 4'hF;  golden_H1[i][j] = 4'hF;
                golden_F2[i][j] = 4'hF;  golden_H2[i][j] = 4'hF;
            end else if (pat_count == 8) begin
                // Divisor 15 Edge Case for Task 0: Forces X1 to be 15
                golden_A[i][j]  = 8'd11;                  golden_B[i][j]  = $urandom_range(0, 255);
                golden_F1[i][j] = 4'd1;                   golden_H1[i][j] = $urandom_range(0, 15);
                golden_F2[i][j] = $urandom_range(0, 15);  golden_H2[i][j] = $urandom_range(0, 15);
            end else if (pat_count == 9) begin
                // Divisor 15 Edge Case for Task 1: Forces X2 to be 15
                golden_A[i][j]  = $urandom_range(0, 255); golden_B[i][j]  = 8'd11;
                golden_F1[i][j] = $urandom_range(0, 15);  golden_H1[i][j] = $urandom_range(0, 15);
                golden_F2[i][j] = 4'd1;                   golden_H2[i][j] = $urandom_range(0, 15);
            end else begin
                // General Randomization
                golden_A[i][j]  = $urandom_range(0, 255);
                golden_B[i][j]  = $urandom_range(0, 255);
                golden_F1[i][j] = $urandom_range(0, 15);
                golden_H1[i][j] = $urandom_range(0, 15);
                golden_F2[i][j] = $urandom_range(0, 15);
                golden_H2[i][j] = $urandom_range(0, 15);
                
                // Specific Overlay for Partial Zeros
                if (pat_count == 4 || pat_count == 5) begin
                    golden_F1[i][j] = 4'h0; golden_F2[i][j] = 4'h0;
                end else if (pat_count == 6 || pat_count == 7) begin
                    golden_H1[i][j] = 4'h0; golden_H2[i][j] = 4'h0;
                end
            end
        end
    end
end endtask

task compute_golden_model;
begin
    if (golden_task_num == 0) begin
        for (r = 0; r < 4; r = r + 1) begin
            for (c = 0; c < 4; c = c + 1) begin
                sum_F = 0;
                sum_H = 0;
                for (k = 0; k < 4; k = k + 1) begin
                    sum_F = sum_F + golden_F1[r][k] * golden_A[k][c];
                    sum_H = sum_H + golden_H1[r][k] * golden_A[k][c];
                end
                X1[r][c] = (sum_F % 15) + 1;
                Y1[r][c] = sum_H % 256;
                
                BX1[r][c]   = X1[r][c] * golden_B[r][c];
                Mid_A[r][c] = golden_A[r][c];
                Mid_B[r][c] = BX1[r][c] ^ Y1[r][c];
            end
        end
        
        for (r = 0; r < 4; r = r + 1) begin
            for (c = 0; c < 4; c = c + 1) begin
                sum_F = 0;
                sum_H = 0;
                for (k = 0; k < 4; k = k + 1) begin
                    sum_F = sum_F + golden_F2[r][k] * Mid_B[k][c];
                    sum_H = sum_H + golden_H2[r][k] * Mid_B[k][c];
                end
                X2[r][c] = (sum_F % 15) + 1;
                Y2[r][c] = sum_H % 256;
                
                Mid_AX2[r][c] = X2[r][c] * Mid_A[r][c];
                
                ans_OUT_A[r*4 + c] = Mid_AX2[r][c] ^ Y2[r][c];
                ans_OUT_B[r*4 + c] = Mid_B[r][c];
            end
        end
        
    end else begin
        for (r = 0; r < 4; r = r + 1) begin
            for (c = 0; c < 4; c = c + 1) begin
                sum_F = 0;
                sum_H = 0;
                for (k = 0; k < 4; k = k + 1) begin
                    sum_F = sum_F + golden_F2[r][k] * golden_B[k][c];
                    sum_H = sum_H + golden_H2[r][k] * golden_B[k][c];
                end
                X2[r][c] = (sum_F % 15) + 1;
                Y2[r][c] = sum_H % 256;
                
                Mid_AX2[r][c] = golden_A[r][c] ^ Y2[r][c];
                Mid_A[r][c]   = Mid_AX2[r][c] / X2[r][c];
                Mid_B[r][c]   = golden_B[r][c];
            end
        end
        
        for (r = 0; r < 4; r = r + 1) begin
            for (c = 0; c < 4; c = c + 1) begin
                sum_F = 0;
                sum_H = 0;
                for (k = 0; k < 4; k = k + 1) begin
                    sum_F = sum_F + golden_F1[r][k] * Mid_A[k][c];
                    sum_H = sum_H + golden_H1[r][k] * Mid_A[k][c];
                end
                X1[r][c] = (sum_F % 15) + 1;
                Y1[r][c] = sum_H % 256;
                
                BX1[r][c] = Mid_B[r][c] ^ Y1[r][c];
                
                ans_OUT_A[r*4 + c] = Mid_A[r][c];
                ans_OUT_B[r*4 + c] = BX1[r][c] / X1[r][c];
            end
        end
    end
end endtask

task wait_gap_task;
begin
    check_idle_en = 1'b1;
    gap = $urandom_range(2, 5);
    repeat(gap) @(negedge clk);
end endtask

task drive_input_task;
begin
    integer in_idx;
    logic [6:0] rand_7;
    logic [3:0] rand_4;
    
    check_idle_en = 1'b0;
    
    in_valid = 1'b1;
    
    rand_7 = $urandom_range(0, 127);
    in_data = {rand_7, golden_task_num};
    @(negedge clk);

    for (in_idx = 0; in_idx < 16; in_idx = in_idx + 1) begin
        in_data = golden_A[in_idx/4][in_idx%4];
        @(negedge clk);
    end
    
    for (in_idx = 0; in_idx < 16; in_idx = in_idx + 1) begin
        in_data = golden_B[in_idx/4][in_idx%4];
        @(negedge clk);
    end
    
    for (in_idx = 0; in_idx < 16; in_idx = in_idx + 1) begin 
        rand_4 = $urandom_range(0, 15);
        in_data = {rand_4, golden_F1[in_idx/4][in_idx%4]};
        @(negedge clk); 
    end
    
    for (in_idx = 0; in_idx < 16; in_idx = in_idx + 1) begin 
        rand_4 = $urandom_range(0, 15);
        in_data = {rand_4, golden_H1[in_idx/4][in_idx%4]};
        @(negedge clk); 
    end
    
    for (in_idx = 0; in_idx < 16; in_idx = in_idx + 1) begin 
        rand_4 = $urandom_range(0, 15);
        in_data = {rand_4, golden_F2[in_idx/4][in_idx%4]};
        @(negedge clk); 
    end
    
    for (in_idx = 0; in_idx < 16; in_idx = in_idx + 1) begin 
        rand_4 = $urandom_range(0, 15);
        in_data = {rand_4, golden_H2[in_idx/4][in_idx%4]};
        @(negedge clk); 
    end
    
    in_valid = 1'b0;
    in_data = 8'bx;
    
end endtask

task wait_out_valid_task;
begin
    current_latency = 0;
    while (out_valid !== 1'b1) begin
        current_latency = current_latency + 1;
        if (current_latency > 200) begin
            $display("************************************************************");
            $display("* [VIOLATION] Execution latency exceeds 200 cycles!        *");
            $display("************************************************************");
            terminate_sim_task();
        end
        @(negedge clk);
    end
    total_latency = total_latency + current_latency;
end endtask

task check_ans_task;
begin
    for (out_count = 0; out_count < 32; out_count = out_count + 1) begin
        if (out_valid !== 1'b1) begin
            $display("************************************************************");
            $display("* [VIOLATION] out_valid MUST be high for 32 continuous !   *");
            $display("************************************************************");
            terminate_sim_task();
        end
        
        if (out_count < 16) begin
            expected_val = ans_OUT_A[out_count];
        end else begin
            expected_val = ans_OUT_B[out_count - 16];
        end
        
        if (out_data !== expected_val) begin
            $display("************************************************************");
            $display("* [VIOLATION] DATA MISMATCH at Pattern NO.%4d             *", pat_count);
            $display("* Output Index : %2d                                         *", out_count);
            $display("* Expected Data: %4h, but your out_data: %4h               *", expected_val, out_data);
            $display("************************************************************");
            terminate_sim_task();
        end
        
        @(negedge clk);
    end
    
    if (out_valid !== 1'b0) begin
        $display("************************************************************");
        $display("* [VIOLATION] out_valid must set to low when invalid       *");
        $display("************************************************************");
        terminate_sim_task();
    end
end endtask

task VERIFICATION_PASSED_TASK;
begin
    $display("\033[38;2;122;98;81;48;2;122;98;81m‚ĖÄ\033[38;2;172;153;136;48;2;172;156;137m‚ĖÄ\033[38;2;195;176;162;48;2;195;177;162m‚ĖÄ\033[38;2;194;177;162;48;2;192;175;161m‚ĖÄ\033[38;2;195;178;163;48;2;193;175;161m‚ĖÄ\033[38;2;193;179;163;48;2;193;176;161m‚ĖÄ\033[38;2;196;185;168;48;2;195;180;164m‚ĖÄ\033[38;2;200;188;174;48;2;198;184;170m‚ĖÄ\033[38;2;201;189;175;48;2;200;186;173m‚ĖÄ\033[38;2;200;189;175;48;2;200;186;173m‚ĖÄ\033[38;2;198;186;172;48;2;199;185;172m‚ĖÄ\033[38;2;197;185;171;48;2;197;183;170m‚ĖÄ\033[38;2;198;183;170;48;2;196;180;166m‚ĖÄ\033[38;2;198;183;170;48;2;193;177;163m‚ĖÄ\033[38;2;200;185;173;48;2;196;180;166m‚ĖÄ\033[38;2;195;181;168;48;2;192;175;161m‚ĖÄ\033[38;2;197;182;169;48;2;194;177;163m‚ĖÄ\033[38;2;199;184;171;48;2;193;175;162m‚ĖÄ\033[38;2;198;182;170;48;2;193;176;162m‚ĖÄ\033[38;2;196;180;165;48;2;190;173;159m‚ĖÄ\033[38;2;194;177;162;48;2;189;171;157m‚ĖÄ\033[38;2;194;177;164;48;2;191;174;160m‚ĖÄ\033[38;2;178;154;140;48;2;177;151;136m‚ĖÄ\033[38;2;139;107;86;48;2;140;107;87m‚ĖÄ\033[38;2;134;102;80;48;2;133;102;81m‚ĖÄ\033[38;2;134;102;81;48;2;134;102;81m‚ĖÄ\033[38;2;128;97;77;48;2;128;96;78m‚ĖÄ\033[38;2;133;113;93;48;2;131;111;93m‚ĖÄ\033[38;2;189;172;155;48;2;184;167;151m‚ĖÄ\033[38;2;192;174;160;48;2;189;171;157m‚ĖÄ\033[38;2;193;175;161;48;2;189;173;157m‚ĖÄ\033[38;2;193;177;162;48;2;193;175;159m‚ĖÄ\033[38;2;189;173;159;48;2;192;172;157m‚ĖÄ\033[38;2;191;175;161;48;2;193;173;158m‚ĖÄ\033[38;2;194;178;163;48;2;189;171;152m‚ĖÄ\033[38;2;196;179;165;48;2;181;164;147m‚ĖÄ\033[38;2;198;179;168;48;2;178;164;145m‚ĖÄ\033[38;2;191;175;160;48;2;183;155;140m‚ĖÄ\033[38;2;197;159;148;48;2;235;176;167m‚ĖÄ\033[38;2;243;179;172;48;2;244;182;172m‚ĖÄ\033[38;2;241;180;169;48;2;242;181;171m‚ĖÄ\033[38;2;242;180;171;48;2;244;181;172m‚ĖÄ\033[38;2;244;181;172;48;2;244;181;172m‚ĖÄ\033[38;2;244;181;172;48;2;243;181;171m‚ĖÄ\033[38;2;243;180;171;48;2;245;182;173m‚ĖÄ\033[38;2;245;182;173;48;2;235;173;164m‚ĖÄ\033[38;2;240;176;168;48;2;220;161;151m‚ĖÄ\033[38;2;241;178;169;48;2;2